```plantuml
@startuml
skinparam class {
    BackgroundColor #F0F0F0
    ArrowColor Black
    BorderColor Black
}

abstract class Iterable {
    <color:darkred>__iter__</color>
}

abstract class Reversible {
    <color:darkred>__reversed__</color>
}

abstract class Sized {
    <color:darkred>__len__</color>
}

abstract class Container {
    <color:darkred>__contains__</color>
}

abstract class Collection {
    <color:darkred>__contains__</color>
    <color:darkred>__iter__</color>
    <color:darkred>__len__</color>
}

abstract class Sequence {
    <color:darkred>__getitem__</color>
    <color:darkred>__len__</color>
    <color:darkblue>__contains__</color>
    <color:darkblue>__iter__</color>
    <color:darkblue>__reversed__</color>
    <color:darkblue>index</color>
    <color:darkblue>count</color>
}

abstract class MutableSequence {
    <color:darkred>__getitem__</color>
    <color:darkred>__setitem__</color>
    <color:darkred>__delitem__</color>
    <color:darkred>__len__</color>
    <color:darkred>insert</color>
    <color:darkblue>__contains__</color>
    <color:darkblue>__iter__</color>
    <color:darkblue>__reversed__</color>
    <color:darkblue>index</color>
    <color:darkblue>count</color>
    <color:darkblue>append</color>
    <color:darkblue>reverse</color>
    <color:darkblue>extend</color>
    <color:darkblue>pop</color>
    <color:darkblue>remove</color>
    <color:darkblue>__iadd__</color>
}

Iterable <|-right- Reversible
Iterable <|-- Collection
Sized <|-right- Collection
Container <|-up- Collection

Reversible <|-right- Sequence
Collection <|-right- Sequence

Sequence <|-right- MutableSequence

@enduml
```
